import React, { useRef, useEffect } from 'react';

function Graph({ results, currentR, onCanvasClick }) {
  const canvasRef = useRef(null);
  const SCALE = 40;
  const CENTER = 200;

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      drawArea(canvas, currentR, results);
    }
  }, [currentR, results]);

  const handleClick = (e) => {
    if (!currentR) {
      alert('Сначала выберите радиус R для проверки точки');
      return;
    }

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();

    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const graphX = (x - CENTER) / SCALE;
    const graphY = (CENTER - y) / SCALE;

    const roundedX = Math.round(graphX * 100) / 100;
    const roundedY = Math.round(graphY * 100) / 100;

    onCanvasClick(roundedX, roundedY);
  };

  const drawArea = (canvas, currentR, points) => {
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, 400, 400);

    drawAxes(ctx);

    // Рисуем область для текущего R
    if (currentR) {
      drawShapes(ctx, currentR);
    }

    // Рисуем ВСЕ точки пользователя
    points.forEach(point => {
      drawPoint(ctx, point.x, point.y, point.hit, point.r, currentR);
    });
  };

  const drawAxes = (ctx) => {
    ctx.strokeStyle = '#2c3e50';
    ctx.lineWidth = 1;
    ctx.fillStyle = '#2c3e50';

    // Ось X
    ctx.beginPath();
    ctx.moveTo(0, CENTER);
    ctx.lineTo(400, CENTER);
    ctx.stroke();

    // Ось Y
    ctx.beginPath();
    ctx.moveTo(CENTER, 0);
    ctx.lineTo(CENTER, 400);
    ctx.stroke();

    // Стрелки
    ctx.beginPath();
    ctx.moveTo(390, CENTER - 5);
    ctx.lineTo(400, CENTER);
    ctx.lineTo(390, CENTER + 5);
    ctx.fill();

    ctx.beginPath();
    ctx.moveTo(CENTER - 5, 10);
    ctx.lineTo(CENTER, 0);
    ctx.lineTo(CENTER + 5, 10);
    ctx.fill();

    // Разметка
    ctx.font = '12px Arial';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';

    // Разметка по X (-5..5)
    for (let i = -5; i <= 5; i++) {
      if (i !== 0) {
        const x = CENTER + i * SCALE;
        ctx.beginPath();
        ctx.moveTo(x, CENTER - 5);
        ctx.lineTo(x, CENTER + 5);
        ctx.stroke();
        ctx.fillText(i.toString(), x, CENTER + 10);
      }
    }

    // Разметка по Y (-5..5)
    ctx.textAlign = 'right';
    ctx.textBaseline = 'middle';
    for (let i = -5; i <= 5; i++) {
      if (i !== 0) {
        const y = CENTER - i * SCALE;
        ctx.beginPath();
        ctx.moveTo(CENTER - 5, y);
        ctx.lineTo(CENTER + 5, y);
        ctx.stroke();
        ctx.fillText(i.toString(), CENTER - 10, y);
      }
    }

    // Подписи осей
    ctx.fillStyle = '#2c3e50';
    ctx.font = '14px Arial';
    ctx.textAlign = 'right';
    ctx.fillText('Y', CENTER - 10, 20);
    ctx.textAlign = 'left';
    ctx.fillText('X', 390, CENTER - 10);
  };

  const drawShapes = (ctx, r) => {
    const scaleR = r * SCALE;
    const scaleRHalf = (r/2) * SCALE;

    ctx.fillStyle = 'rgba(52, 152, 219, 0.4)';
    ctx.strokeStyle = '#3498db';
    ctx.lineWidth = 2;

    // 1. Часть круга в 1-й четверти (радиус R/2)
    ctx.beginPath();
    ctx.arc(CENTER, CENTER, scaleRHalf, -Math.PI/2, 0, false);
    ctx.lineTo(CENTER, CENTER);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // 2. Треугольник во 2-й четверти: (0,0), (-R,0), (0,R)
    ctx.beginPath();
    ctx.moveTo(CENTER, CENTER); // (0,0)
    ctx.lineTo(CENTER - scaleR, CENTER); // (-R,0)
    ctx.lineTo(CENTER, CENTER - scaleR); // (0,R) - минус потому что Y вверх
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    // 3. Прямоугольник в 3-й четверти: (0,0), (-R/2,0), (0,-R), (-R/2,-R)
    ctx.beginPath();
    ctx.rect(CENTER - scaleRHalf, CENTER, scaleRHalf, scaleR);
    ctx.fill();
    ctx.stroke();
  };

   const drawPoint = (ctx, x, y, hit, pointR, currentR) => {
      const pointX = CENTER + x * SCALE;
      const pointY = CENTER - y * SCALE;

      // Размер точки зависит от того, совпадает ли её R с текущим
      const radius = (currentR && pointR === currentR) ? 6 : 4;
      const borderWidth = (currentR && pointR === currentR) ? 2 : 1;

      ctx.beginPath();
      ctx.arc(pointX, pointY, radius, 0, Math.PI * 2);

      // Цвет: зеленый - попадание, красный - промах
      ctx.fillStyle = hit ? '#27ae60' : '#e74c3c';
      ctx.fill();

      // Обводка: толстая если точка для текущего R
      ctx.strokeStyle = (currentR && pointR === currentR) ? '#2c3e50' : '#7f8c8d';
      ctx.lineWidth = borderWidth;
      ctx.stroke();

      // Если R точки отличается от текущего, показываем маленький текст с R
      if (currentR && pointR !== currentR) {
        ctx.fillStyle = '#2c3e50';
        ctx.font = '10px Arial';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(`R=${pointR}`, pointX, pointY - 10);
      }
    };

  return (
      <div className="graph-container">
        <h3>Область проверки {currentR ? `(R = ${currentR})` : ''}</h3>
        <canvas
          ref={canvasRef}
          width="400"
          height="400"
          onClick={handleClick}
          className="area-canvas"
          style={{ cursor: currentR ? 'crosshair' : 'not-allowed' }}
        />
        <p className="graph-hint">
          {currentR
            ? 'Кликните на график для проверки точки с текущим R'
            : 'Выберите радиус R для проверки точки'}
        </p>
        <div className="legend">
          <div className="legend-item">
            <div className="legend-color current-hit"></div>
            <span>Попадание (текущий R)</span>
          </div>
          <div className="legend-item">
            <div className="legend-color current-miss"></div>
            <span>Промах (текущий R)</span>
          </div>
          <div className="legend-item">
            <div className="legend-color other-hit"></div>
            <span>Попадание (другой R)</span>
          </div>
          <div className="legend-item">
            <div className="legend-color other-miss"></div>
            <span>Промах (другой R)</span>
          </div>
        </div>
      </div>
    );
  }

  export default Graph;
